// Extract task context from PM
const taskRequest = $input.item.json.body;

const task_id = taskRequest.task_id;
const task_title = taskRequest.task_title;
const task_description = taskRequest.task_description;
const task_phase = taskRequest.task_phase;
const assignee = taskRequest.assignee;
const context_questions = taskRequest.context_questions || [];
const user_inputs = taskRequest.user_inputs || {};
const depends_on = taskRequest.depends_on || [];
const shared_memory = taskRequest.shared_memory;

// Load project memory (last 20 entries)
const projectMemory = await $supabase.query(
  'SELECT * FROM project_memory WHERE project_id = $1 ORDER BY created_at DESC LIMIT 20',
  [shared_memory.project_id]
);

// Load brand memory
const brandMemory = await $supabase.query(
  'SELECT * FROM brand_memory WHERE project_id = $1',
  [shared_memory.project_id]
);

return {
  json: {
    task_id,
    task_title,
    task_description,
    task_phase,
    assignee,
    context_questions,
    user_inputs,
    depends_on,
    shared_memory,
    project_memory: projectMemory.rows,
    brand_memory: brandMemory.rows[0] || {},
  }
};

// Parse Milo's response for write-back commands
const miloResponse = $input.item.json;
const responseText = miloResponse.text || miloResponse.content;

// Extract commands (pattern: COMMAND: XXX)
const commandPattern = /COMMAND: ([A-Z_]+)[\s\S]*?REASON: ([^\n]+)[\s\S]*?PAYLOAD: (\{[\s\S]*?\})/g;
const commands = [];

let match;
while ((match = commandPattern.exec(responseText)) !== null) {
  const [_, command, reason, payloadStr] = match;
  try {
    const payload = JSON.parse(payloadStr);
    commands.push({
      command,
      reason,
      payload
    });
  } catch (e) {
    console.error('Failed to parse command payload:', e);
  }
}

return {
  json: {
    agent_response: {
      message: responseText.split('COMMAND:')[0].trim(),
      agent_used: 'milo',
      commands,
      raw_response: responseText
    },
    task_context: $('Extract Task Context').item.json
  }
};

// Execute each write-back command
const { commands } = $input.item.json.agent_response;
const taskContext = $input.item.json.task_context;

for (const cmd of commands) {
  switch (cmd.command) {
    case 'ADD_FILE':
      await $supabase.query(
        'INSERT INTO project_files (project_id, file_type, file_name, file_base64, metadata, created_by) VALUES ($1, $2, $3, $4, $5, $6)',
        [
          taskContext.shared_memory.project_id,
          cmd.payload.file_type,
          cmd.payload.file_name,
          cmd.payload.file_base64,
          cmd.payload.metadata,
          'milo'
        ]
      );
      break;

    case 'UPDATE_TASK_STATUS':
      await $supabase.query(
        'UPDATE tasks SET status = $1, completion_notes = $2, updated_at = NOW() WHERE id = $3',
        [
          cmd.payload.status,
          cmd.payload.completion_notes,
          cmd.payload.task_id
        ]
      );
      break;

    case 'MEMORY_WRITE':
      await $supabase.query(
        'INSERT INTO project_memory (project_id, agent_id, memory_type, content, recommendations) VALUES ($1, $2, $3, $4, $5)',
        [
          taskContext.shared_memory.project_id,
          'milo',
          cmd.payload.memory_type,
          cmd.payload.content,
          cmd.payload.recommendations
        ]
      );
      break;

    case 'NOTIFY_USER':
      // Trigger notification (Supabase Realtime or email)
      await $supabase.query(
        'INSERT INTO notifications (project_id, message, attachments, created_by) VALUES ($1, $2, $3, $4)',
        [
          taskContext.shared_memory.project_id,
          cmd.payload.message,
          cmd.payload.attachments,
          'milo'
        ]
      );
      break;

    case 'REQUEST_TASK':
      await $supabase.query(
        'INSERT INTO tasks (project_id, title, description, assignee, priority, depends_on, status) VALUES ($1, $2, $3, $4, $5, $6, $7)',
        [
          taskContext.shared_memory.project_id,
          cmd.payload.task_title,
          cmd.payload.task_description,
          'milo',
          cmd.payload.priority,
          cmd.payload.depends_on,
          'todo'
        ]
      );
      break;
  }
}

return {
  json: {
    success: true,
    commands_executed: commands.length,
    agent_response: $input.item.json.agent_response
  }
};
